from tkinter import ttk, filedialog, messagebox
import pandas as pd
import json
import os
import sys
import traceback
from allocation_core import allocate_add_order, generate_result_dataframe, load_config, DEFAULT_CONFIG

def setup_encoding():
    try:
        if sys.platform == 'win32':
            sys.stdout.reconfigure(encoding='utf-8')
            sys.stderr.reconfigure(encoding='utf-8')
    except:
        pass

class AllocationApp:
    def __init__(self, root):
        self.root = root
        self.root.title("加单商品分配系统")
        self.root.geometry("1100x850")
        self.root.configure(bg="#F8F9FA")
        self.root.minsize(1000, 700)
        
        self.config = None
        try:
            self.config = load_config()
        except Exception as e:
            self.config = DEFAULT_CONFIG
            print(f"Warning: Using default config: {e}")
        
        self.file_path = None
        self.result_df = None
        self.reason_df = None
        
        self.stage_colors = [
            ("#E7F0FF", "#2563EB"),
            ("#E6FFE7", "#059669"),
            ("#FFF7E6", "#D97706"),
            ("#F3E8FF", "#7C3AED"),
        ]
        
        self.stage_list = [
            ("broken_size_fix", "断码修复"),
            ("sales_match", "销量匹配"),
            ("sell_through_priority", "销尽率优先")
        ]
        
        self.setup_styles()
        self.create_widgets()
    
    def setup_styles(self):
        style = ttk.Style()
        style.theme_use("clam")
        
        style.configure("Title.TLabel", font=("PingFang SC", "Microsoft YaHei", 24, "bold"), background="#F8F9FA", foreground="#111827")
        style.configure("Section.TLabelframe", font=("PingFang SC", "Microsoft YaHei", 14, "bold"), background="#F8F9FA", borderwidth=0)
        style.configure("Section.TLabelframe.Label", font=("PingFang SC", "Microsoft YaHei", 14, "bold"), foreground="#111827", background="#F8F9FA")
        style.configure("Config.TLabel", font=("PingFang SC", "Microsoft YaHei", 12), background="#F8F9FA", foreground="#4B5563")
        style.configure("Status.TLabel", font=("PingFang SC", "Microsoft YaHei", 12), background="#F8F9FA", foreground="#4B5563")
        
        style.configure("Treeview", font=("PingFang SC", "Microsoft YaHei", 11), rowheight=32, background="#FFFFFF", foreground="#1F2937", borderwidth=0)
        style.configure("Treeview.Heading", font=("PingFang SC", "Microsoft YaHei", 11, "bold"), background="#F3F4F6", foreground="#374151", borderwidth=0)
        style.map("Treeview", background=[("selected", "#E5E7EB")], foreground=[("selected", "#111827")])
    
    def create_widgets(self):
        main_container = tk.Frame(self.root, bg="#F8F9FA")
        main_container.pack(fill=tk.BOTH, expand=True, padx=32, pady=28)
        
        self.create_header_section(main_container)
        self.create_main_content_section(main_container)
    
    def create_header_section(self, parent):
        header_frame = tk.Frame(parent, bg="#F8F9FA")
        header_frame.pack(fill=tk.X, pady=(0, 20))
        
        title_frame = tk.Frame(header_frame, bg="#F8F9FA")
        title_frame.pack(side=tk.LEFT, fill=tk.X)
        
        title_label = tk.Label(title_frame, text="加单商品分配系统", font=("PingFang SC", "Microsoft YaHei", 26, "bold"), bg="#F8F9FA", fg="#111827")
        title_label.pack(anchor=tk.W)
        
        subtitle_label = tk.Label(title_frame, text="基于智能算法的库存分配工具", font=("PingFang SC", "Microsoft YaHei", 13), bg="#F8F9FA", fg="#6B7280")
        subtitle_label.pack(anchor=tk.W, pady=(4, 0))
        
        version_label = tk.Label(header_frame, text="v2.3", font=("PingFang SC", "Microsoft YaHei", 12), bg="#F8F9FA", fg="#9CA3AF")
        version_label.pack(side=tk.RIGHT, anchor=tk.S)
    
    def create_main_content_section(self, parent):
        content_frame = tk.Frame(parent, bg="#F8F9FA")
        content_frame.pack(fill=tk.BOTH, expand=True)
        
        left_column = tk.Frame(content_frame, bg="#F8F9FA")
        left_column.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=(0, 16))
        
        right_column = tk.Frame(content_frame, bg="#F8F9FA")
        right_column.pack(side=tk.RIGHT, fill=tk.BOTH, expand=True, padx=(16, 0))
        
        self.create_file_upload_section(left_column)
        self.create_config_section(left_column)
        self.create_logic_section(right_column)
        self.create_button_section(right_column)
        self.create_status_section(parent)
        self.create_result_section(parent)
    
    def create_card_frame(self, parent, title="", with_padding=True):
        card = tk.Frame(parent, bg="#FFFFFF", highlightbackground="#E5E7EB", highlightcolor="#E5E7EB", highlightthickness=1)
        
        if title:
            title_frame = tk.Frame(card, bg="#FFFFFF")
            title_frame.pack(fill=tk.X, pady=(16, 8), padx=20)
            tk.Label(title_frame, text=title, font=("PingFang SC", "Microsoft YaHei", 15, "bold"), bg="#FFFFFF", fg="#111827").pack(side=tk.LEFT)
        
        content_frame = tk.Frame(card, bg="#FFFFFF")
        if with_padding:
            content_frame.pack(fill=tk.X, padx=20, pady=(0, 16))
        
        return card, content_frame
    
    def create_file_upload_section(self, parent):
        card, content = self.create_card_frame(parent, "📁 文件上传")
        
        upload_frame = tk.Frame(content, bg="#FFFFFF")
        upload_frame.pack(fill=tk.X)
        
        upload_area = tk.Frame(upload_frame, bg="#F9FAFB", highlightbackground="#D1D5DB", highlightcolor="#3B82F6", highlightthickness=1)
        upload_area.pack(fill=tk.X, pady=(8, 16), ipady=28)
        
        tk.Label(upload_area, text="📤", font=("Arial", 28), bg="#F9FAFB", fg="#6B7280").pack(pady=(4, 8))
        tk.Label(upload_area, text="拖放或点击上传Excel文件", font=("PingFang SC", "Microsoft YaHei", 13, "bold"), bg="#F9FAFB", fg="#374151").pack()
        tk.Label(upload_area, text="支持 .xlsx, .xlsm 格式", font=("PingFang SC", "Microsoft YaHei", 11), bg="#F9FAFB", fg="#9CA3AF").pack(pady=(2, 0))
        upload_area.bind("<Button-1>", lambda e: self.browse_file())
        upload_area.config(cursor="hand2")
        
        self.file_entry = tk.Entry(upload_frame, font=("PingFang SC", "Microsoft YaHei", 11), bg="#F3F4F6", relief=tk.FLAT, borderwidth=0, highlightthickness=1, highlightbackground="#E5E7EB", highlightcolor="#3B82F6", disabledbackground="#F3F4F6")
        self.file_entry.pack(fill=tk.X, pady=(0, 8), ipady=10)
        
        browse_btn = self.create_button(upload_frame, "选择文件", style="primary")
        browse_btn.pack(fill=tk.X, pady=(0, 0))
        browse_btn.config(command=self.browse_file)
    
    def create_config_section(self, parent):
        card, content = self.create_card_frame(parent, "⚙️ 参数配置")
        
