            level_frame = tk.Frame(entry_container, bg="#FFFFFF")
            level_frame.pack(side=tk.LEFT, padx=(0 if i == 0 else 10, 0))
            
            tk.Label(level_frame, text=level, font=("PingFang SC", "Microsoft YaHei", 10), bg="#FFFFFF", fg="#6B7280").pack(side=tk.LEFT, padx=(0, 4))
            
            entry = tk.Entry(level_frame, width=6, font=("PingFang SC", "Microsoft YaHei", 11), justify="center", bg="#F9FAFB", relief=tk.FLAT, borderwidth=0, highlightthickness=1, highlightbackground="#E5E7EB", highlightcolor="#3B82F6")
            entry.pack(side=tk.LEFT, ipady=6)
            
