    def create_config_section(self, parent):
        card, content = self.create_card_frame(parent, "⚙️ 参数配置")
        
        self.config_expanded = False
        
        toggle_frame = tk.Frame(content, bg="#FFFFFF")
        toggle_frame.pack(fill=tk.X, pady=(8, 0))
        
        self.config_toggle = tk.Label(toggle_frame, text="▼ 展开详情", font=("PingFang SC", "Microsoft YaHei", 11), bg="#FFFFFF", fg="#6B7280", cursor="hand2")
        self.config_toggle.pack(side=tk.LEFT)
        self.config_toggle.bind("<Button-1>", self.toggle_config)
        
        self.config_content = tk.Frame(content, bg="#FFFFFF")
        
        levels = ["SA", "A", "B", "C", "D", "OL"]
        
        self._create_config_row(self.config_content, "覆盖周期（天）", levels, self.config, "coverage_days", "coverage_entries")
        self._create_config_row(self.config_content, "等级权重", levels, self.config, "level_weights", "weight_entries")
        self._create_config_row(self.config_content, "安全系数", levels, self.config, "safety_factors", "safety_entries")
        self._create_config_row(self.config_content, "最小目标库存", levels, self.config, "min_target_inventory", "min_target_entries")
        
        stage_priority_frame = tk.Frame(self.config_content, bg="#FFFFFF")
        stage_priority_frame.pack(fill=tk.X, pady=(16, 0))
        
        tk.Label(stage_priority_frame, text="阶段优先级", font=("PingFang SC", "Microsoft YaHei", 12, "bold"), bg="#FFFFFF", fg="#111827").pack(anchor=tk.W, pady=(0, 10))
        
        stage_display_frame = tk.Frame(stage_priority_frame, bg="#FFFFFF")
        stage_display_frame.pack(fill=tk.X)
        
        self.stage_labels = []
        self.stage_display_frame = stage_display_frame
        current_priority = self.config.get("allocation_config", {}).get("stage_priority", ["broken_size_fix", "sales_match", "sell_through_priority"])
        
        for i, stage_id in enumerate(current_priority):
            self._create_stage_item(i, stage_id)
        
        btn_frame = tk.Frame(self.config_content, bg="#FFFFFF")
        btn_frame.pack(fill=tk.X, pady=(16, 0))
        
        reset_btn = self.create_button(btn_frame, "恢复默认", style="secondary")
        reset_btn.pack(side=tk.RIGHT)
        reset_btn.config(command=self.reset_config)
        
        save_btn = self.create_button(btn_frame, "保存配置", style="primary")
        save_btn.pack(side=tk.RIGHT, padx=(10, 0))
        save_btn.config(command=self.save_config)
    
    def _create_config_row(self, parent, label_text, levels, config, config_key, entry_attr_name):
        frame = tk.Frame(parent, bg="#FFFFFF")
        frame.pack(fill=tk.X, pady=(0, 12))
        
        tk.Label(frame, text=label_text, font=("PingFang SC", "Microsoft YaHei", 12, "bold"), bg="#FFFFFF", fg="#111827").pack(anchor=tk.W, pady=(0, 6))
        
        entries = {}
        entry_container = tk.Frame(frame, bg="#FFFFFF")
        entry_container.pack(fill=tk.X)
        
        config_dict = config.get("allocation_config", {}).get(config_key, {})
        
        for i, level in enumerate(levels):
            level_frame = tk.Frame(entry_container, bg="#FFFFFF")
            level_frame.pack(side=tk.LEFT, padx=(0 if i == 0 else 10, 0))
            
            tk.Label(level_frame, text=level, font=("PingFang SC", "Microsoft YaHei", 10), bg="#FFFFFF", fg="#6B7280").pack(side=tk.LEFT, padx=(0, 4))
            
            entry = tk.Entry(level_frame, width=6, font=("PingFang SC", "Microsoft YaHei", 11), justify="center", bg="#F9FAFB", relief=tk.FLAT, borderwidth=0, highlightthickness=1, highlightbackground="#E5E7EB", highlightcolor="#3B82F6")
            entry.pack(side=tk.LEFT, ipady=6)
            
            default = 14 if config_key == "coverage_days" else 1.0 if config_key == "level_weights" else 0.3 if config_key == "safety_factors" else 0
            entry.insert(0, str(config_dict.get(level, default)))
            entries[level] = entry
        
        setattr(self, entry_attr_name, entries)
    
